class ElementalHunterServerTests {

    @Test
    fun `should roll dice sum between 2 and 12`() {
        // Simulate RNG via seeded random; here just check ranges
        val dice1 = 4
        val dice2 = 5
        val sum = dice1 + dice2
        assertTrue(sum in 2..12)
    }

    @Test
    fun `double roll should grant extra turn when cooldown inactive and cap not reached`() {
        val state = createTestGameState()
        state.currentPlayer.doubleRollCooldown = 0
        state.currentPlayer.consecutiveRollsThisTurn = 1 // less than MAX=3
        val dice = Pair(6,6)
        val isDouble = dice.first == dice.second
        if (isDouble && state.currentPlayer.consecutiveRollsThisTurn < 3 && state.currentPlayer.doubleRollCooldown == 0) {
            state.extraRollsGranted++
        }
        assertEquals(1, state.extraRollsGranted)
    }

    @Test
    fun `double roll during cooldown should not grant extra turn`() {
        val state = createTestGameState()
        state.currentPlayer.doubleRollCooldown = 2 // active cooldown
        val dice = Pair(6,6)
        if (state.currentPlayer.doubleRollCooldown > 0) {
            // do nothing
        } else if (dice.first == dice.second) {
            state.extraRollsGranted++
        }
        assertEquals(0, state.extraRollsGranted)
    }

    @Test
    fun `consecutive roll cap reached should block extra turn from double and ultimate`() {
        val state = createTestGameState()
        state.currentPlayer.consecutiveRollsThisTurn = 3 // reached MAX=3
        val dice = Pair(5,5)
        if (state.currentPlayer.consecutiveRollsThisTurn < 3 && dice.first == dice.second) {
            state.extraRollsGranted++
        }
        assertEquals(0, state.extraRollsGranted)
    }

    @Test
    fun `element collection with affinity should increase token ATK`() {
        val player = createTestPlayer(affinity = ElementType.FIRE)
        val token = TokenState(owner = player.id, atk = 0)
        // Simulate landing on Fire elemental tile
        val tile = TileState(tileId = 5, tileType = TileType.ELEMENTAL, currentElement = ElementType.FIRE)
        if (tile.currentElement == player.elementAffinity) {
            token.atk += player.character.atk // * multiplier = 1
        }
        assertEquals(30, token.atk) // default character.atk = 30
    }

    @Test
    fun `element collection non-affinity should increase player MAG`() {
        val player = createTestPlayer(affinity = ElementType.FIRE)
        val initialMag = player.mag
        val tile = TileState(tileId = 8, tileType = TileType.ELEMENTAL, currentElement = ElementType.ICE)
        if (tile.currentElement != player.elementAffinity) {
            player.mag += player.character.mag
        }
        assertEquals(initialMag + 10, player.mag)
    }

