        val player = createTestPlayer()
        player.elementQueue.addAll(listOf(ElementType.FIRE, ElementType.ICE, ElementType.GRASS))
        val maxQueue = 5 // for test; actual TBD
        player.elementQueue.add(ElementType.ROCK)
        if (player.elementQueue.size > maxQueue) {
            player.elementQueue.removeAt(0)
        }
        assertEquals(listOf(ElementType.ICE, ElementType.GRASS, ElementType.ROCK), player.elementQueue)
    }

    @Test
    fun `combo C3 (Triple Threat) should remove three identical elements and apply Tier1 reward`() {
        val state = createTestGameState()
        val player = state.currentPlayer
        player.elementQueue.addAll(listOf(ElementType.FIRE, ElementType.FIRE, ElementType.FIRE))
        // Detect combo (simplified)
        val combo = detectCombo(player.elementQueue)
        assertNotNull(combo)
        assertEquals("C3", combo.type)
        // Apply reward
        player.tokens.forEach { it.atk += BalanceConfig.COMBO_T1_ATK_BONUS }
        // Remove combo elements
        repeat(3) { player.elementQueue.removeAt(combo.startIndex) }
        assertTrue(player.elementQueue.isEmpty())
        assertEquals(3, player.tokens.sumOf { it.atk }) // each token +150? Actually each token ATK increase individually
    }

