    @Test
    fun `kick should reduce defender HP and push to nearest safe zone behind`() {
        val state = createTestGameState()
        val attacker = state.currentPlayer.tokens[0].apply { atk = 50 }
        val defender = state.opponent.tokens[0].apply { position = 10 }
        val defenderInitialHP = state.opponent.hp
        // Simulate kick
        state.opponent.hp -= attacker.atk
        val newPos = findNearestSafeZoneBackward(defender.position)
        assertEquals(defenderInitialHP - 50, state.opponent.hp)
        assertTrue(newPos in SAFE_ZONE_IDS)
    }

    @Test
    fun `kick on safe zone should not occur`() {
        val tile = TileState(tileId = 51, tileType = TileType.SAFE_ZONE)
        val shouldKick = tile.tileType != TileType.SAFE_ZONE
        assertFalse(shouldKick)
    }

    @Test
    fun `final goal processing should add chosen element and attack opponent then return to safe zone`() {
        val state = createTestGameState()
        val token = state.currentPlayer.tokens[0].apply { position = FINAL_GOAL_ID }
        val opponentInitialHP = state.opponent.hp
        // Process final goal
        player.elementQueue.add(ElementType.ICE) // player chooses element
        // Attack opponent: opponent HP -= token.atk
        state.opponent.hp -= token.atk
        // Token returns to safe zone
        token.position = PLAYER_SAFE_ZONE_ID
        // Check results
        assertTrue(state.opponent.hp < opponentInitialHP)
        assertEquals(PLAYER_SAFE_ZONE_ID, token.position)
    }

