fun detectCombo(queue: List<ElementType>): ComboResult? {
    // Simplified: returns first C3 found
    for (i in 0 until queue.size - 2) {
        if (queue[i] == queue[i+1] && queue[i] == queue[i+2]) {
            return ComboResult(type = "C3", startIndex = i, elements = listOf(queue[i], queue[i+1], queue[i+2]))
        }
    }
    return null
}

