fun findNearestSafeZoneBackward(tileId: Int): Int {
    // Simplified backward search in MAIN_LOOP reversed
    MAIN_LOOP.reversed().forEach { if (SAFE_ZONE_IDS.contains(it)) return it }
    return SAFE_ZONE_IDS.first()
}

val MAIN_LOOP = (0..60).toList() // placeholder

fun executeArtifact(player: PlayerState, artifactType: String) {
    when (artifactType) {
        "Swap" -> {
            require(player.elementQueue.size >= 2) { "Queue must have at least 2 elements for Swap" }
            // perform swap
        }
        "Charge" -> {
            player.elementQueue.add(player.elementAffinity)
        }
        else -> throw IllegalArgumentException("Unknown artifact: $artifactType")
    }
}

fun getAvailableArtifacts(player: PlayerState): List<String> {
    val list = mutableListOf<String>()
    if (player.emptyTileVisits >= 1) list.add("Swap")
    if (player.emptyTileVisits >= 2) list.add("Change")
    if (player.emptyTileVisits >= 3) list.add("Charge")
    return list
}

// Data classes (simplified)
data class GameState(
    val matchId: String,
    val currentPlayer: PlayerState,
    val opponent: PlayerState,
    val board: List<TileState>,
    val maxRounds: Int,
    var currentRound: Int,
    var winner: String? = null
) {
    fun determineWinner() {
        if (currentRound >= maxRounds) {
            winner = if (currentPlayer.hp > opponent.hp) currentPlayer.id else if (opponent.hp > currentPlayer.hp) opponent.id else "P2"
        }
    }
}

data class PlayerState(
    val id: String,
    var hp: Int,
    var mag: Int,
    val elementAffinity: ElementType,
    val elementQueue: MutableList<ElementType>,
    val tokens: MutableList<TokenState>,
    val character: CharacterConfig,
    var doubleRollCooldown: Int = 0,
    var consecutiveRollsThisTurn: Int = 0,
    var ultimateExtraRolls: Int = 0,
    var emptyTileVisits: Int = 0,
    var kickCount: Int = 0,
    var finishedHorseCount: Int = 0,
    var extraRollsGranted: Int = 0
)

data class TokenState(
    val owner: String,
    var position: Int,
    var atk: Int,
    var frozenRounds: Int
)

data class TileState(
    val tileId: Int,
    val tileType: TileType,
    val baseElement: ElementType? = null,
    val currentElement: ElementType? = null
)

enum class TileType { ELEMENTAL, EMPTY, SAFE_ZONE, START }

enum class ElementType { FIRE, ICE, GRASS, ROCK }

data class CharacterConfig(
    val affinity: ElementType,
    val atk: Int,
    val mag: Int,
    val hp: Int
)

data class ComboResult(val type: String, val startIndex: Int, val elements: List<ElementType>)
